        }

        // fee_records の paid_amount も同期更新
        if (billingData) {
          const currentYear = new Date().getFullYear();
          const { data: existingRecord } = await supabase
            .from('fee_records')
            .select('id')
            .eq('roster_id', billingData.roster_id)
            .eq('year', currentYear)
            .single();

